/** Найти страницу по slug */
export function getPageBySlug(slug: string): ContentPage | undefined {
  return contentPages.find((p) => p.slug === slug);
}

/** Получить страницы по категории */
export function getPagesByCategory(category: string): ContentPage[] {
  return contentPages.filter((p) => p.category === category);
}

